let taskList = [];

function renderTasks() {
  let taskListEl = document.getElementById("task-list");
  taskListEl.innerHTML = "";
  for (let i = 0; i < taskList.length; i++) {
    let taskEl = document.createElement("li");
    taskEl.innerText = taskList[i];
    taskListEl.appendChild(taskEl);
  }
}

function addTask() {
  let taskInput = prompt("Enter task:");
  if (taskInput) {
    taskList.push(taskInput);
    renderTasks();
  }
}

document.addEventListener("DOMContentLoaded", function () {
  document.getElementById("add-task-btn").addEventListener("click", addTask);
});
```
This code creates a basic popup window with a list of tasks and a button to add a new task. The `renderTasks()` function is used to display the tasks in the popup window. The `addTask()` function is used to prompt the user to enter a new task and add it to the task list. The `DOMContentLoaded` event listener is used to execute the `addTask()` function when the page is fully loaded.Question 5: Add the following code to the popup.html file:
